	--1.Top 3 Customers with the Highest Total Balance Across All Accounts 
select * from customers
select * from accounts
select top 3 
    c.CustomerID,
    c.FullName,
    sum(a.Balance) as TotalBalance
FROM Customers c
JOIN Accounts a 
    ON c.CustomerID = a.CustomerID
group by 
    c.CustomerID, 
    c.FullName
ORDER BY 
    TotalBalance DESC




---2.Customers Who Have More Than One Active Loan

select * from loans
select * from customers


select 
	c.customerID,
	c.FullName,
	count(l.LoanID) as ActiveLoancount
from customers as c 
join Loans as l
on c.customerID=l.customerID
where l.Status='Active'
group by
	c.customerID,
	c.FullNAMe
having count(l.loanID)>1


---3.Transactions That Were Flagged as Fraudulent- tranzaksiyalar shubhali deb kimga tegishli ,risk darajasi


select * from customers
select * from transactions
select * from frauddetection


select 
    f.FraudID,
    c.CustomerID,
    c.FullName,
    f.TransactionID,
    f.RiskLevel,
    f.ReportedDate
from  FraudDetection as f
JOIN Customers as c 
    ON f.CustomerID = c.CustomerID;




--4.Total Loan Amount Issued Per Branch  

select * from loans

select * from customers

select * from accounts

select * from	branches



select 
    b.BranchID,
    b.BranchName,
    SUM(l.Amount) as TotalLoanAmount
from Loans as l
JOIN Customers as c 
    on l.CustomerID = c.CustomerID
JOIN Accounts as a 
   on c.CustomerID = a.CustomerID
JOIN Branches as b 
    on a.BranchID = b.BranchID
group by  
    b.BranchID, 
    b.BranchName;


--5.Customers who made multiple large transactions (above $10,000) within a short time frame (less than 1 hour apart)
select * from transactions
select * from customers
select * from accounts

select
    c.CustomerID,
    c.FullName,
    count(t.TransactionID) as LargeTransactionCount
FROM Transactions t
JOIN Accounts as a 
    on t.AccountID = a.AccountID
JOIN Customers as c 
    ON a.CustomerID = c.CustomerID
WHERE t.Amount > 5000
GROUP BY 
    c.CustomerID,
    c.FullName
HAVING COUNT(t.TransactionID) > 1;



--6.Customers who have made transactions from different countries within 10 minutes

select * from transactions
select * from Branches
select * from Accounts
select * from customers

SELECT DISTINCT
    c.CustomerID,
    c.FullName
FROM Transactions t1
JOIN Transactions t2 
    ON t1.AccountID = t2.AccountID
    AND t1.TransactionID <> t2.TransactionID
    AND ABS(DATEDIFF(MINUTE, t1.Date, t2.Date)) <=10
JOIN Accounts a1 ON t1.AccountID = a1.AccountID
JOIN Accounts a2 ON t2.AccountID = a2.AccountID
JOIN Branches b1 ON a1.BranchID = b1.BranchID
JOIN Branches b2 ON a2.BranchID = b2.BranchID
JOIN Customers c ON a1.CustomerID = c.CustomerID
WHERE b1.Country <> b2.Country;




